  ('disabled-c5fb3965-moex-00309', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關行政法人之敘述，下列何者錯誤？', '["行政法人，指國家及地方自治團體，為執行特定公共事務，依法律或自 治條例設立之公法人", "行政法人應擬訂人事管理、會計制度、內部控制、稽核作業及其他規章， 報請監督機關備查", "行政法人設董（理）事會者，置董（理）事長一人，由董（理）事依章 程選舉產生後聘任", "行政法人設董（理）事會者，得置執行長一人，負責行政法人營運及管 理業務之執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00310', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-110-d1a761c9', 'sub-disabled-c5fb3965-02', NULL, 'single_choice', '有關地方自治團體與上級監督機關之敘述，下列何者錯誤？', '["地方自治團體之違法行政處分，得由自治監督機關予以撤銷、變更、廢 止或停止其執行", "地方自治團體依法應作為而不作為，致嚴重危害公益或妨礙地方政務正 常運作，其適於代行處理者，得分別由監督機關命其於一定期限內為之", "地方自治團體對監督機關所命其於一定期限內履行職務之處分如認為 窒礙難行時，應向行政法院請求暫停執行該處分", "直轄市政府辦理自治事項違背憲法、法律或基於法律授權之法規者，由 中央各該主管機關報行政院予以撤銷、變更、廢止或停止其執行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:57+00:00", "source_pdf_sha1": "6e41655acede", "answer_pdf_sha1": "bbcc6f9a3cef", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
